package router

import (
	"context"
	"fmt"
	"net/http"
	"os"
	"time"

	"github.com/gin-gonic/gin"
	"golang.org/x/net/http2"
	"golang.org/x/net/http2/h2c"
	"k8s.io/klog/v2"

	"github.com/volcano-sh/agentcube/pkg/store"
)

type Config struct {
	Port                  string
	Debug                 bool
	EnableTLS             bool
	TLSCert               string
	TLSKey                string
	MaxConcurrentRequests int
}

type Server struct {
	config         *Config
	engine         *gin.Engine
	httpServer     *http.Server
	sessionManager SessionManager
	storeClient    store.Store
	httpTransport  *http.Transport
	jwtManager     *JWTManager
}

func NewServer(config *Config) (*Server, error) {
	httpTransport := &http.Transport{
		IdleConnTimeout:    0,
		DisableCompression: false,
	}

	if _, err := http2.ConfigureTransports(httpTransport); err != nil {
		klog.Warningf("Failed to configure HTTP/2 transport: %v", err)
	}

	storeClient := store.Storage()

	sessionManager, err := NewSessionManager(storeClient)
	if err != nil {
		return nil, fmt.Errorf("failed to create session manager: %w", err)
	}

	jwtManager, err := NewJWTManager()
	if err != nil {
		return nil, fmt.Errorf("failed to create JWT manager: %w", err)
	}

	ctx := context.Background()
	if err := jwtManager.TryStoreOrLoadJWTKeySecret(ctx); err != nil {
		klog.Warningf("Failed to store/load JWT key secret: %v", err)
	}

	if !config.Debug {
		gin.SetMode(gin.ReleaseMode)
	}

	engine := gin.New()
	engine.Use(gin.Logger(), gin.Recovery())

	maxConcurrentRequests := config.MaxConcurrentRequests
	if maxConcurrentRequests <= 0 {
		maxConcurrentRequests = 1000
	}

	server := &Server{
		config:         config,
		engine:         engine,
		sessionManager: sessionManager,
		storeClient:    storeClient,
		httpTransport:  httpTransport,
		jwtManager:     jwtManager,
	}

	server.setupRoutes()

	h2s := &http2.Server{}
	httpServer := &http.Server{
		Addr:              ":" + config.Port,
		Handler:           h2c.NewHandler(engine, h2s),
		ReadTimeout:       30 * time.Second,
		IdleTimeout:       90 * time.Second,
		ReadHeaderTimeout: 10 * time.Second,
	}

	server.httpServer = httpServer

	return server, nil
}

func (s *Server) Start() error {
	if s.config.EnableTLS {
		if _, err := os.Stat(s.config.TLSCert); os.IsNotExist(err) {
			return fmt.Errorf("TLS certificate file does not exist: %s", s.config.TLSCert)
		}
		if _, err := os.Stat(s.config.TLSKey); os.IsNotExist(err) {
			return fmt.Errorf("TLS key file does not exist: %s", s.config.TLSKey)
		}

		klog.Infof("Starting HTTPS server on port %s", s.config.Port)
		return s.httpServer.ListenAndServeTLS(s.config.TLSCert, s.config.TLSKey)
	}

	klog.Infof("Starting HTTP server on port %s", s.config.Port)
	return s.httpServer.ListenAndServe()
}

func (s *Server) Shutdown(ctx context.Context) error {
	klog.Info("Shutting down router server...")
	return s.httpServer.Shutdown(ctx)
}

func (s *Server) handleHealthLive(c *gin.Context) {
	c.JSON(http.StatusOK, gin.H{"status": "alive"})
}

func (s *Server) handleHealthReady(c *gin.Context) {
	if s.sessionManager == nil {
		c.JSON(http.StatusServiceUnavailable, gin.H{"error": "session manager not initialized"})
		return
	}
	c.JSON(http.StatusOK, gin.H{"status": "ready"})
}

