func (s *Server) handleAgentInvoke(c *gin.Context) {
	namespace := c.Param("namespace")
	name := c.Param("name")
	kind := types.AgentRuntimeKind
	path := c.Param("path")

	sessionID := c.GetHeader("x-agentcube-session-id")

	sandbox, err := s.sessionManager.GetSandboxBySession(c.Request.Context(), sessionID, namespace, name, kind)
	if err != nil {
		handleGetSandboxError(c, err)
		return
	}

	if err := s.storeClient.UpdateSessionLastActivity(c.Request.Context(), sandbox.SessionID, time.Now()); err != nil {
		klog.Warningf("Failed to update last activity: %v", err)
	}

	s.forwardToSandbox(c, sandbox, path, sessionID)
}

func (s *Server) handleCodeInterpreterInvoke(c *gin.Context) {
	namespace := c.Param("namespace")
	name := c.Param("name")
	kind := types.CodeInterpreterKind
	path := c.Param("path")

	sessionID := c.GetHeader("x-agentcube-session-id")

	sandbox, err := s.sessionManager.GetSandboxBySession(c.Request.Context(), sessionID, namespace, name, kind)
	if err != nil {
		handleGetSandboxError(c, err)
		return
	}

	if err := s.storeClient.UpdateSessionLastActivity(c.Request.Context(), sandbox.SessionID, time.Now()); err != nil {
		klog.Warningf("Failed to update last activity: %v", err)
	}

	s.forwardToSandbox(c, sandbox, path, sessionID)
}

func (s *Server) forwardToSandbox(c *gin.Context, sandbox *types.SandboxInfo, path, sessionID string) {
	if len(sandbox.EntryPoints) == 0 {
		c.JSON(http.StatusNotFound, gin.H{"error": "no entry point found for sandbox"})
		return
	}

	var upstreamURL string
	for _, ep := range sandbox.EntryPoints {
		if ep.Path != "" && strings.HasPrefix(path, "/"+ep.Path) {
			upstreamURL = ep.Endpoint
			break
		}
	}

	if upstreamURL == "" {
		upstreamURL = sandbox.EntryPoints[0].Endpoint
	}

	if !strings.HasPrefix(upstreamURL, "http://") && !strings.HasPrefix(upstreamURL, "https://") {
		protocol := "http://"
		if sandbox.EntryPoints[0].Protocol == "HTTPS" {
			protocol = "https://"
		}
		upstreamURL = protocol + upstreamURL
	}

	targetURL, err := url.Parse(upstreamURL)
	if err != nil {
		klog.Errorf("Failed to parse upstream URL: %v", err)
		c.JSON(http.StatusInternalServerError, gin.H{"error": "invalid upstream URL"})
		return
	}

	proxy := httputil.NewSingleHostReverseProxy(targetURL)
	proxy.Transport = s.httpTransport

	originalDirector := proxy.Director
	proxy.Director = func(req *http.Request) {
		originalDirector(req)
		req.URL.Path = path
		if req.URL.Path == "" {
			req.URL.Path = "/"
		}
		req.URL.RawPath = ""
		req.Host = targetURL.Host

		req.Header.Set("X-Forwarded-Host", c.Request.Host)
		if c.Request.TLS != nil {
			req.Header.Set("X-Forwarded-Proto", "https")
		} else {
			req.Header.Set("X-Forwarded-Proto", "http")
		}

		clientIP := c.ClientIP()
		if forwarded := c.Request.Header.Get("X-Forwarded-For"); forwarded != "" {
			req.Header.Set("X-Forwarded-For", forwarded+", "+clientIP)
		} else {
			req.Header.Set("X-Forwarded-For", clientIP)
		}

		if sandbox.Kind == types.SandboxKind || sandbox.Kind == types.SandboxClaimsKind {
			token, err := s.jwtManager.GenerateToken(map[string]interface{}{
				"session_id": sessionID,
			})
			if err != nil {
				klog.Errorf("Failed to sign JWT: %v", err)
				c.JSON(http.StatusInternalServerError, gin.H{"error": "failed to sign request", "code": "JWT_SIGNING_FAILED"})
				return
			}
			req.Header.Set("Authorization", "Bearer "+token)
		}
	}

	proxy.ModifyResponse = func(resp *http.Response) error {
		resp.Header.Set("x-agentcube-session-id", sessionID)
		return nil
	}

	proxy.ErrorHandler = func(w http.ResponseWriter, r *http.Request, err error) {
		klog.Errorf("Proxy error: %v", err)
		errStr := err.Error()
		if strings.Contains(errStr, "connection refused") {
			w.WriteHeader(http.StatusBadGateway)
			w.Write([]byte(`{"error":"sandbox unreachable"}`))
		} else if strings.Contains(errStr, "timeout") {
			w.WriteHeader(http.StatusGatewayTimeout)
			w.Write([]byte(`{"error":"sandbox timeout"}`))
		} else {
			w.WriteHeader(http.StatusBadGateway)
			w.Write([]byte(`{"error":"sandbox unreachable"}`))
		}
	}

	if err := s.storeClient.UpdateSessionLastActivity(c.Request.Context(), sessionID, time.Now()); err != nil {
		klog.Warningf("Failed to update last activity after forward: %v", err)
	}

	proxy.ServeHTTP(c.Writer, c.Request)
}

func handleGetSandboxError(c *gin.Context, err error) {
	if status, ok := err.(errors.APIStatus); ok {
		code := int(status.Status().Code)
		message := status.Status().Message
		if message == "" {
			message = err.Error()
		}
		if code == 500 {
			message = "internal server error"
		}
		c.JSON(code, gin.H{"error": message})
		return
	}

	klog.Errorf("Unhandled error: %v", err)
	c.JSON(http.StatusInternalServerError, gin.H{"error": "internal server error"})
}

func (s *Server) handleGetSandboxError(c *gin.Context, err error) {
	handleGetSandboxError(c, err)
}

func (s *Server) UpdateSessionLastActivity(ctx context.Context, sessionID string) error {
	return s.storeClient.UpdateSessionLastActivity(ctx, sessionID, time.Now())
}

