package workloadmanager

import (
	"context"
	"fmt"
	"net/http"
	"os"
	"os/signal"
	"syscall"
	"time"

	"github.com/gin-gonic/gin"
	"golang.org/x/net/http2"
	"golang.org/x/net/http2/h2c"
	"k8s.io/client-go/kubernetes"
	"k8s.io/klog/v2"
	"sigs.k8s.io/controller-runtime/pkg/client/config"

	"github.com/volcano-sh/agentcube/pkg/store"
)

type Server struct {
	config          *Config
	router          *gin.Engine
	httpServer      *http.Server
	k8sClient       *kubernetes.Clientset
	sandboxReconciler *SandboxReconciler
	tokenCache      *TokenCache
	storeClient     store.Store
	wg              chan struct{}
}

func NewServer(config *Config) (*Server, error) {
	k8sClient, err := initializeK8sClient()
	if err != nil {
		return nil, fmt.Errorf("failed to initialize k8s client: %w", err)
	}

	storeClient := store.Storage()

	tokenCache := NewTokenCache(1000, 5*time.Minute)

	server := &Server{
		config:     config,
		k8sClient:  k8sClient,
		tokenCache: tokenCache,
		storeClient: storeClient,
		wg:         make(chan struct{}),
	}

	server.setupRoutes()

	return server, nil
}

func initializeK8sClient() (*kubernetes.Clientset, error) {
	cfg, err := config.GetConfig()
	if err != nil {
		return nil, err
	}

	cfg.QPS = 50
	cfg.Burst = 100

	return kubernetes.NewForConfig(cfg)
}

func (s *Server) setupRoutes() {
	gin.SetMode(gin.ReleaseMode)
	s.router = gin.New()
	s.router.Use(gin.Logger(), gin.Recovery())

	s.router.GET("/health", s.handleHealth)
	s.router.POST("/v1/agent-runtime", s.handleAgentRuntimeCreate)
	s.router.DELETE("/v1/agent-runtime/sessions/:sessionId", s.handleDeleteSandbox)
	s.router.POST("/v1/code-interpreter", s.handleCodeInterpreterCreate)
}

func (s *Server) handleHealth(c *gin.Context) {
	c.JSON(http.StatusOK, gin.H{"status": "healthy"})
}

func (s *Server) Start() error {
	h2s := &http2.Server{}
	httpServer := &http.Server{
		Addr:         fmt.Sprintf(":%d", s.config.Port),
		Handler:      h2c.NewHandler(s.router, h2s),
		ReadTimeout:  15 * time.Second,
		IdleTimeout:  90 * time.Second,
	}

	s.httpServer = httpServer

	if s.config.EnableTLS {
		if _, err := os.Stat(s.config.TLSCert); os.IsNotExist(err) {
			return fmt.Errorf("TLS certificate file does not exist: %s", s.config.TLSCert)
		}
		if _, err := os.Stat(s.config.TLSKey); os.IsNotExist(err) {
			return fmt.Errorf("TLS key file does not exist: %s", s.config.TLSKey)
		}

		klog.Infof("Starting HTTPS server on port %d", s.config.Port)
		return httpServer.ListenAndServeTLS(s.config.TLSCert, s.config.TLSKey)
	}

	klog.Infof("Starting HTTP server on port %d", s.config.Port)
	return httpServer.ListenAndServe()
}

func (s *Server) Shutdown(ctx context.Context) error {
	klog.Info("Shutting down workload manager server...")
	if s.httpServer != nil {
		return s.httpServer.Shutdown(ctx)
	}
	return nil
}

func (s *Server) StartBackgroundWorkers(ctx context.Context) {
	gc := newGarbageCollector(s.storeClient, 15*time.Second)
	go gc.Run(ctx)
}

func (s *Server) loggingMiddleware() gin.HandlerFunc {
	return gin.Logger()
}

func (s *Server) authMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		if !s.config.EnableAuth {
			c.Next()
			return
		}

		authHeader := c.GetHeader("Authorization")
		if authHeader == "" {
			c.JSON(http.StatusUnauthorized, gin.H{"error": "missing authorization header"})
			c.Abort()
			return
		}

		token := authHeader
		if len(authHeader) > 7 && authHeader[:7] == "Bearer " {
			token = authHeader[7:]
		}

		if username, saName, namespace, ok := s.tokenCache.Get(token); ok {
			c.Set("username", username)
			c.Set("serviceAccount", saName)
			c.Set("namespace", namespace)
			c.Next()
			return
		}

		c.Next()
	}
}

